() => {
  // Patch fetch to intercept auth/tier and return max tier
  const origFetch = window.fetch;
  window.fetch = function(url, opts) {
    const urlStr = typeof url === 'string' ? url : url.toString();

    if (urlStr.includes('/api/auth/tier')) {
      return Promise.resolve(new Response(JSON.stringify({
        tier: 'max',
        features: {
          sentiment_filter: true,
          ai_ticker_recommendations: true,
          deduplication: true,
          api_access: true,
          advanced_search: true
        }
      }), { status: 200, headers: { 'Content-Type': 'application/json' } }));
    }

    // Pass everything else through (but strip auth header requirement)
    return origFetch(url, opts);
  };

  // Patch SignalAuth to simulate signed-in state
  window.SignalAuth.getUser = () => ({
    uid: 'test-max-user',
    email: 'test@instnews.net',
    displayName: 'Max Test User',
    photoURL: null,
  });
  window.SignalAuth.isSignedIn = () => true;
  window.SignalAuth.getToken = () => 'test-token';
  window.SignalAuth.fetch = function(url, opts) {
    opts = opts || {};
    opts.headers = opts.headers || {};
    opts.headers['Authorization'] = 'Bearer test-token';
    return window.fetch(url, opts);
  };

  return 'Patched';
}

