async (page) => {
  // Intercept /api/auth/tier to return max tier
  await page.route('**/api/auth/tier', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        tier: 'max',
        features: {
          sentiment_filter: true,
          ai_ticker_recommendations: true,
          deduplication: true,
          api_access: true,
          advanced_search: true
        }
      })
    });
  });

  // Navigate to terminal
  await page.goto('http://localhost:5173/terminal.html');
  await page.waitForTimeout(2000);

  // Hide auth/upgrade gates
  await page.evaluate(() => {
    const authGate = document.getElementById('auth-gate');
    const upgradeGate = document.getElementById('upgrade-gate');
    if (authGate) authGate.style.display = 'none';
    if (upgradeGate) upgradeGate.style.display = 'none';
  });

  // Patch SignalAuth and trigger tier fetch
  await page.evaluate(() => {
    window.SignalAuth.getUser = () => ({
      uid: 'test-max-user',
      email: 'test@instnews.net',
      displayName: 'Max Test User',
      photoURL: null,
    });
    window.SignalAuth.isSignedIn = () => true;
    window.SignalAuth.getToken = () => 'test-token';

    const origFetch = window._origFetch || window.fetch;
    window._origFetch = origFetch;

    window.SignalAuth.fetch = function(url, opts) {
      opts = opts || {};
      opts.headers = opts.headers || {};
      opts.headers['Authorization'] = 'Bearer test-token';
      return origFetch(url, opts);
    };
  });

  // Now trigger the auth change callbacks by dispatching a custom event
  // or directly calling initAuth-like flow by clicking sign-in related elements
  // Let's try triggering the onAuthChange callbacks via SignalAuth
  const result = await page.evaluate(() => {
