  // Intercept /api/auth/signin to return a fake successful login
  await page.route('**/api/auth/signin', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        token: 'fake-max-test-token',
        user: {
          email: 'test@instnews.net',
          display_name: 'Max Test User',
          photo_url: null
        }
      })
    });
  });

  // Now trigger signInWithEmail — this will:
  // 1. Hit our intercepted /api/auth/signin → get fake token
  // 2. Set _currentUser and _appToken internally
  // 3. Call _notifyAuthChange() which triggers terminal-app.js fetchTier()
  // 4. fetchTier() hits our intercepted /api/auth/tier → gets max tier
  const result = await page.evaluate(async () => {
    try {
      const data = await window.SignalAuth.signInWithEmail('test@instnews.net', 'test123');
      return { success: true, data };
    } catch(e) {
      return { success: false, error: e.message || String(e) };
    }
  });

  // Wait for the tier fetch and re-render to complete
  await page.waitForTimeout(3000);

  return result;
}

