        user: {
          email: 'test@instnews.net',
          display_name: 'Max Test User',
          photo_url: null
        }
      })
    });
  });

  // Trigger sign-in to re-fire auth change callbacks and fetchTier
  const signin = await page.evaluate(async () => {
    try {
      const data = await window.SignalAuth.signInWithEmail('test@instnews.net', 'test123');
      return { success: true };
    } catch(e) {
      return { success: false, error: String(e) };
    }
  });

  await page.waitForTimeout(3000);

  // Check headers and ticker badges
  const result = await page.evaluate(() => {
    const headers = Array.from(document.querySelectorAll('th')).map(th => th.textContent.trim());
    const tickerBadges = document.querySelectorAll('.ticker-badge');
    const tickerData = Array.from(tickerBadges).slice(0, 10).map(el => ({
      text: el.textContent.trim(),
      dataTicker: el.getAttribute('data-ticker'),
      cursor: getComputedStyle(el).cursor
    }));
    return { signin, headers, tickerBadgeCount: tickerBadges.length, tickerBadges: tickerData };
  });

  return result;
}

