async (page) => {
  // Clear all existing route handlers
  await page.unrouteAll();

  // Intercept /api/auth/me
  await page.route('**/api/auth/me', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        user: {
          email: 'test@instnews.net',
          display_name: 'Max Test User',
          photo_url: null
        }
      })
    });
  });

  // Intercept /api/auth/tier
  await page.route('**/api/auth/tier', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        tier: 'max',
        features: {
          sentiment_filter: true,
          ai_ticker_recommendations: true,
          deduplication: true,
          api_access: true,
          advanced_search: true
        }
      })
    });
  });

  // Ensure the fake token is in localStorage
  await page.evaluate(() => {
    localStorage.setItem('signal_app_token', 'fake-max-test-token');
    // Also ensure ticker column is visible
    localStorage.setItem('signal_column_visibility', JSON.stringify({
      time: true, sentiment: true, source: true, headline: true,
      summary: false, ticker: true, confidence: false, risk: false, tradeable: false
    }));
  });

  // Reload — the token will be found in localStorage,
  // /api/auth/me will return 200, _notifyAuthChange fires,
  // terminal-app calls fetchTier which returns max tier
  await page.reload({ waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);

  // Check state
  const result = await page.evaluate(() => {
    const headers = Array.from(document.querySelectorAll('th')).map(th => th.textContent.trim());
    const tickerBadges = document.querySelectorAll('.ticker-badge');
    const tickerData = Array.from(tickerBadges).slice(0, 15).map(el => ({
      text: el.textContent.trim(),
      dataTicker: el.getAttribute('data-ticker'),
      cursor: getComputedStyle(el).cursor
    }));
    const authGateVisible = document.getElementById('auth-gate')?.style.display !== 'none' 
      && document.getElementById('auth-gate')?.offsetParent !== null;
    const upgradeGateVisible = document.getElementById('upgrade-gate')?.style.display !== 'none'
      && document.getElementById('upgrade-gate')?.offsetParent !== null;

    return {
      headers,
      tickerBadgeCount: tickerBadges.length,
      tickerBadges: tickerData,
      authGateVisible,
      upgradeGateVisible,
    };
  });

  return result;
}

