() => {
  const rows = document.querySelectorAll('tbody tr');
  const tickerRows = [];
  rows.forEach((row, i) => {
    const tickerCell = row.querySelector('.cell-ticker');
    if (tickerCell) {
      const badge = tickerCell.querySelector('.ticker-badge');
      if (badge) {
        tickerRows.push({
          index: i,
          ticker: badge.getAttribute('data-ticker'),
          text: badge.textContent.trim(),
          cursor: getComputedStyle(badge).cursor,
          headline: row.querySelector('.cell-headline')?.textContent.trim().substring(0, 60)
        });
      }
    }
  });

  // Also count em-dashes
  const dashCount = document.querySelectorAll('.cell-ticker .cell-dash').length;

  return {
    totalRows: rows.length,
    tickerBadgeRows: tickerRows,
    dashCount,
    tickerBadgeCount: tickerRows.length
  };
}

